import type { CSSObject, Theme } from "@mui/material/styles";
import { InfoSlotStyles } from "../info-basic/info";

export const getInfoN04Styles = (
  arg: Theme | { theme: Theme },
): CSSObject & Partial<InfoSlotStyles> => {
  const theme = "theme" in arg ? arg.theme : arg;
  return {
    eyebrow: {
      display: "block",
      textAlign: "center",
      color: "#9e9e9e",
      letterSpacing: "2px",
      fontSize: 14,
      marginTop: 12,
    },
    title: {
      textAlign: "center",
      fontSize: 32,
      lineHeight: 2,
      fontWeight: 300,
      fontFamily:
        '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol"',
      marginBottom: "0.72em",
      "&:after": {
        content: '""',
        width: 24,
        height: 2,
        backgroundColor: "#ddd",
        display: "block",
        margin: "8px auto",
        borderRadius: 2,
      },
    },
    subtitle: {
      textAlign: "center",
      fontSize: 14,
      color: "#222",
      lineHeight: 1.75,
      width: "88%",
      margin: "0 auto",
      ...theme.applyStyles("dark", {
        color: "#999",
      }),
    },
  };
};

import React from "react";
import { Info } from "../info-basic/info";
import { InfoEyebrow } from "../info-basic/info-eyebrow";
import { InfoSubtitle } from "../info-basic/info-subtitle";
import { InfoTitle } from "../info-basic/info-title";
import { getInfoN04Styles } from "./info-n04.styles";

export function InfoN04() {
  return (
    <Info variant="n04" useStyles={getInfoN04Styles}>
      <InfoEyebrow>Kesha</InfoEyebrow>
      <InfoTitle>Inner Varnika</InfoTitle>
      <InfoSubtitle>
        That year, collection of songs, review melodies, memories full, this is
        a long and warm journey
      </InfoSubtitle>
    </Info>
  );
}
